import React from 'react';
import {KitsInputMask, KitsInputText} from "../../../../_compat";
import type {FieldValues} from "react-hook-form";
import type {UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
// ...

export const InputText = <T extends FieldValues>({
                                                     element, control, getValues, fieldLogic,
                                                 }: UseFieldLogicElementProps<T>) => {

    // The hook does all the heavy lifting.
    const {
        field,
        placeholder,
        isRequired,
        isDisabled, fieldState,
        label, helperText, rightAddon, leftAddon, withMask, keyFilter,
        layout, hideError, attached,
        isShown,
        style: elementStyle,
        slots,
        localProps = {}
    } = fieldLogic;

    if (withMask) {
        return (
            <KitsInputMask
                {...field}
                id={field.name}
                placeholder={placeholder}
                required={isRequired}
                disabled={isDisabled}
                errors={fieldState.error?.message}
                invalid={fieldState.invalid}
                hideError={hideError}
                helperText={helperText}
                leftAddon={leftAddon}
                rightAddon={rightAddon}
                label={label}
                attached={attached}
                style={elementStyle?.input}
                containerStyle={elementStyle?.container}
                slots={slots}
                {...localProps}
            />
        )
    } else {
        // Pass keyboardType from element definition (native-only, no-op on web)
        const keyboardType = 'keyboardType' in element ? (element as any).keyboardType : undefined;
        return (
            <KitsInputText
                {...field}
                id={field.name}
                placeholder={placeholder}
                required={isRequired}
                disabled={isDisabled}
                hideError={hideError}
                helperText={helperText}
                leftAddon={leftAddon}
                rightAddon={rightAddon}
                keyFilter={keyFilter}
                keyboardType={keyboardType}
                label={label}
                attached={attached}
                errors={fieldState.error?.message}
                invalid={fieldState.invalid}
                style={elementStyle?.input}
                containerStyle={elementStyle?.container}
                slots={slots}
                {...localProps}
            />
        )
    }
};

export default InputText;
